const weatherNode = $('Météo du jour').first().json;
const emailItems = $('Emails non lus').all();

let weatherSummary;
try {
  if (weatherNode.error || !weatherNode.main) {
    weatherSummary = 'Météo temporairement indisponible';
  } else {
    weatherSummary = `${weatherNode.weather[0].description}, ${Math.round(weatherNode.main.temp)}°C (ressenti ${Math.round(weatherNode.main.feels_like)}°C)`;
  }
} catch(e) {
  weatherSummary = 'Météo indisponible';
}

let emailSummary;
try {
  if (!emailItems.length || emailItems[0].json.error) {
    emailSummary = 'Emails non disponibles pour le moment.';
  } else {
    const emails = emailItems.filter(e => !e.json.error);
    emailSummary = emails.length === 0
      ? 'Aucun email non lu.'
      : emails.map(e => {
          const from = e.json.payload?.headers?.find(h => h.name === 'From')?.value?.split('<')[0]?.trim() || 'Inconnu';
          return `• ${from}: ${(e.json.snippet || '').substring(0, 80)}...`;
        }).join('\n');
  }
} catch(e) {
  emailSummary = 'Erreur lecture emails.';
}

const now = new Date();
const greeting = now.getHours() < 12 ? 'Bonjour' : 'Bonsoir';
const dateStr = now.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' });

return [{ json: {
  briefing: `${greeting} Abo ! Nous sommes le ${dateStr}.\n\n🌤️ Météo : ${weatherSummary}.\n\n📧 Emails importants :\n${emailSummary}`,
  weather: weatherSummary,
  email_count: emailItems.filter(e => !e.json.error).length
}}];
